cpp.code:
#include <iostream>
using namespace std;

int main() {
    int scores[5] = {45, 82, 91, 60, 77};
    int passing = 0;
    for (int i = 0; i < 5; i++) {
        if (scores[i] >= 70) {
            passing = passing + 1;
        }
    }
    cout << passing;
    return 0;
}
